create table dirkspzm32.lvs_lam_bh_hist (
    sid                  varchar2(2 char) not null enable,
    firma_nr             number(2, 0) not null enable,
    vorg_id              number(*, 0) not null enable,
    vorg_typ             varchar2(2 char) not null enable,
    lam_bh_id            number(*, 0) not null enable,
    lam_id               number(*, 0) not null enable,
    artikel_id           number(*, 0),
    bus                  number(*, 5),
    buch_datum           date,
    ls_login_id          number(*, 0),
    lgr_platz            varchar2(30 char),
    lte_id               varchar2(20 char),
    lhm_id               varchar2(20 char),
    charge_id            number(*, 0),
    serie_id             number(*, 0),
    abnr                 varchar2(20 char),
    menge                number(*, 3),
    lam_bh_kg            number(*, 6),
    lam_bh_kg_einheit    number(*, 6),
    res_id               number(*, 0),
    leitzahl             number(*, 5),
    fa_ag                number(*, 5),
    fa_upos              number(*, 5),
    abnr_extern          varchar2(20 char),
    vorgang_id           number(*, 0),
    li_nr                number(*, 5),
    li_pos_nr            number(*, 5),
    created_date         date,
    created_login_id     number(*, 0),
    last_change_date     date,
    last_change_login_id number(*, 0),
    change_menge         number(*, 3),
    owner_address_id     number(*, 0),
    owner_address_id_new number(*, 0)
);

alter table dirkspzm32.lvs_lam_bh_hist
    add constraint pk_lam_bh_hist primary key ( lam_bh_id )
        using index enable;


